 en:{name:'English',nav:{features:'Features',integrations:'Integrations',pricing:'Pricing',docs:'Documentation',faq:'FAQ'},cta:{early:'Get Early Access',demo:'Watch Demo'},hero:{title:'The QA agent <span>that learns</span> your workflow.',subtitle:'Turn rough test notes into polished, reviewed bug tickets — filed to your tracker in seconds.'},metrics:{saved:'saved per bug',dupe:'dupe check',setup:'setup',private:'by design',savedNum:'~10 min',dupeNum:'Auto',setupNum:'~15 min',privateNum:'Private'},under:{features:'✓ All features included',updates:'✓ Free v1.x updates',private:'✓ Private by design'},mission:{style:'Project style loaded',severity:'Severity matrix loaded',glossary:'Glossary synced',duplicate:'Duplicate search enabled',redaction:'PII redaction enabled',generating:'Generating report...'},report:{label:'GENERATED BUG REPORT',title:'Login button becomes unresponsive after rapid taps',severity:'High',preview:'Jira preview',summaryTitle:'Summary',summary:'The login button stops responding when clicked repeatedly during authentication. User remains on login screen without error feedback.',pre:'Steps to Reproduce\n1. Open login page\n2. Enter valid credentials\n3. Click Login rapidly\n4. Observe button state\n\nExpected: User logs in once.\nActual: Button locks and login fails.',ready:'Preview ready. Waiting for your confirmation.'},demo:{eyebrow:'SEE IT WORK',title:'One agent. Different QA worlds.',subtitle:'Use it for web, mobile, desktop, SaaS, enterprise workflows or games.',saas:'SaaS / Web App',game:'Game QA',general:'General Workflow'},integrations:{eyebrow:'WORKS WITH YOUR TOOLS',title:'Connect what you already use.',lede:'Jira and Azure DevOps include built-in tested field mapping. Other trackers and tools connect through your own MCP server.',builtin:'BUILT-IN TESTED MAPPING',mcp:'VIA YOUR MCP SERVER',crash:'CRASH & TEST',knowledge:'KNOWLEDGE & COLLAB',note:'⌁ Flip on any tool in setup. Connect once. Use everywhere.'},pricing:{soloTitle:'EARLY ACCESS · LIMITED',teamTitle:'TEAM LICENSE · LIMITED',seats:'5 SEATS',perYear:'/year',limited:'Limited time price',soloRegular:'Regular price $59.99/year',teamRegular:'Regular price $249.99/year',soloDevice:'1 device (one user)',allFeatures:'All features included',updates:'Free v1.x updates while active',docs:'Documentation & guides',support:'Email support',teamDevices:'5 devices (5 users)',teamWorkflow:'Shared QA workflow',teamConfig:'Shared project configuration',teamSeverity:'Consistent severity & categories',teamTools:'Team setup tools',priority:'Priority support',teamCta:'Get Team License'},trust:{privateTitle:'▣ Private by Design',private:'Your work stays on your machine. We never store, train on, or sell your data.',telemetryTitle:'◌ No Telemetry',telemetry:'Only anonymous license checks to keep your license active.',previewTitle:'✓ Preview Before Filing',preview:'You review every ticket and type “yes” to file.',backupsTitle:'◎ Local Backups',backups:'Your settings and activity stay on your machine. Easy backups anytime.',updatesTitle:'◇ Secure Updates',updates:'Updates are cryptographically signed and verified before installation.',vscodeTitle:'</> Runs in VS Code',vscode:'Native to VS Code. No other apps needed.'},faq:{title:'Launch details, without surprises.',items:[['Does BugIt file automatically?','No. Every ticket and comment is previewed first, and you must type “yes” before anything is filed.'],['Which trackers have built-in tested mapping?','Jira and Azure DevOps have built-in tested field mapping. Other trackers and tools connect through your own MCP server.'],['Do I need GitHub Copilot?','GitHub Copilot is recommended and easiest. BugIt can also run standalone with your own OpenAI or Anthropic key.'],['Can I use Claude, Gemini or GPT?','Yes. Inside GitHub Copilot, use the models available to your Copilot plan. Standalone mode supports your own OpenAI or Anthropic key.'],['Does Taskivator see my work?','No. Your bug reports, specs, glossary, screenshots and settings are never sent to Taskivator.'],['What is included in Team?','Team includes 5 devices for 5 users, shared QA workflow, shared project configuration, consistent severity and categories, team setup tools, and priority support.'],['Can I practice without filing?','Yes. Use dry run to generate a full report without creating tickets, comments or notifications.'],['Can I customize BugIt?','Yes. You can configure your glossary, categories, platforms, house style and tracker settings for your project.'],['Does BugIt support screenshots?','Yes. Paste an image into chat and review the generated report before filing.'],['How do updates work?','BugIt backs up your settings, verifies signed updates, and preserves your setup.'],['What happens when my license expires?','You keep your local files and settings. Filing features require an active license.'],['How do I get support?','Email the in-app Support page. Please do not send confidential project information.']]},docs:{eyebrow:'DOCUMENTATION',getting:'Getting Started',gettingDesc:'Set up BugIt in minutes.',user:'User Guide',userDesc:'Complete guide to features and workflows.',license:'License Agreement',licenseDesc:'Read the terms for using BugIt.',privacy:'Privacy Policy',privacyDesc:'How we collect, use and protect your data.',faqDesc:'Answers to common questions.',support:'Support',supportDesc:'Get help and open a support ticket.'},docPages:{homeTitle:'Documentation',homeIntro:'Everything you need to install, activate, customize and use BugIt safely.',gettingTitle:'Getting Started',userTitle:'User Guide',licenseTitle:'License Agreement',privacyTitle:'Privacy Policy',faqTitle:'FAQ',supportTitle:'Support',supportIntro:'Need help with setup or licensing? Email the in-app Support page.',download:'Download PDF',before:'Before sending',beforeText:'Please do not include confidential source code, customer data, private tickets or secrets.',sections:['Install VS Code and GitHub Copilot, open the BugIt folder, select the BugIt QA Agent, paste your license key, then type Begin setup.','The user guide covers setup, everyday commands, customization, updates, backups, safety and troubleshooting. BugIt previews every report and files only after approval.','BugIt is licensed, not sold. Solo is one device at a time. Team includes 5 devices for 5 users. Free v1.x updates are included while the license is active.','Taskivator does not receive your bug reports, specs, glossary, screenshots, code, settings or tickets. Only anonymous license checks are used.']}}
