function merge(a,b){const r=structuredClone(a);for(const k in b){if(b[k]&&typeof b[k]==='object'&&!Array.isArray(b[k]))r[k]=merge(r[k]||{},b[k]);else r[k]=b[k]}return r}
function add(code,obj){i18n[code]=merge(i18n.en,obj)}
