add('pt-br',merge(i18n.es,{name:'Português BR',nav:{features:'Recursos',integrations:'Integrações',pricing:'Preços',docs:'Documentação',faq:'FAQ'},cta:{early:'Acesso antecipado',demo:'Ver demo'},hero:{title:'O agente QA que <span>aprende</span> seu fluxo de trabalho.',subtitle:'Transforme notas de teste em tickets limpos e revisados, enviados ao seu tracker em segundos.'},pricing:{soloTitle:'ACESSO ANTECIPADO · LIMITADO',teamTitle:'LICENÇA DE EQUIPE · LIMITADA',seats:'5 ASSENTOS',perYear:'/ano',limited:'Preço por tempo limitado',soloRegular:'Preço normal US$59,99/ano',teamRegular:'Preço normal US$249,99/ano',teamCta:'Obter licença de equipe'},faq:{title:'Detalhes do lançamento, sem surpresas.',items:i18n.es.faq.items.map(([q,a])=>[q.replace('¿','').replace('?','?'),a])},docs:{getting:'Primeiros passos',user:'Guia do usuário',license:'Contrato de licença',privacy:'Política de privacidade',support:'Suporte'}}));
add('it',merge(i18n.es,{name:'Italiano',nav:{features:'Funzioni',integrations:'Integrazioni',pricing:'Prezzi',docs:'Documentazione',faq:'FAQ'},cta:{early:'Accesso anticipato',demo:'Guarda demo'},hero:{title:'L’agente QA che <span>impara</span> il tuo workflow.',subtitle:'Trasforma note di test grezze in ticket puliti e revisionati, inviati al tracker in pochi secondi.'},pricing:{soloTitle:'ACCESSO ANTICIPATO · LIMITATO',teamTitle:'LICENZA TEAM · LIMITATA',seats:'5 POSTI',perYear:'/anno',limited:'Prezzo per tempo limitato',soloRegular:'Prezzo normale $59.99/anno',teamRegular:'Prezzo normale $249.99/anno',teamCta:'Ottieni licenza Team'},faq:{title:'Dettagli di lancio, senza sorprese.',items:i18n.es.faq.items.map(([q,a])=>[q.replace('¿','').replace('BugIt crea incidencias','BugIt crea ticket').replace('?','?'),a])},docs:{getting:'Introduzione',user:'Guida utente',license:'Contratto di licenza',privacy:'Informativa sulla privacy',support:'Supporto'}}));
add('ko',merge(i18n.ja,{name:'한국어',nav:{features:'기능',integrations:'연동',pricing:'가격',docs:'문서',faq:'FAQ'},cta:{early:'얼리 액세스',demo:'데모 보기'},hero:{title:'워크플로를 <span>학습하는</span> QA 에이전트.',subtitle:'간단한 테스트 메모를 검토된 깔끔한 버그 티켓으로 바꾸고 몇 초 안에 트래커로 보냅니다.'},pricing:{soloTitle:'얼리 액세스 · 한정',teamTitle:'팀 라이선스 · 한정',seats:'5석',perYear:'/년',limited:'기간 한정 가격',soloRegular:'정가 $59.99/년',teamRegular:'정가 $249.99/년',teamCta:'팀 라이선스 받기'},faq:{title:'구매 전 궁금한 점을 명확하게.',items:[['BugIt이 자동으로 버그를 등록하나요?','아니요. 모든 티켓과 댓글은 먼저 미리보기로 표시되며, 등록 전 반드시 “yes”를 입력해야 합니다.'],['내장 테스트 매핑이 있는 트래커는 무엇인가요?','Jira와 Azure DevOps는 내장된 검증済み 필드 매핑을 제공합니다. 다른 도구는 자체 MCP 서버로 연결합니다.'],['GitHub Copilot이 필요한가요?','권장되며 가장 쉽습니다. 자체 OpenAI 또는 Anthropic 키로 독립 실행도 가능합니다.'],['Claude, Gemini 또는 GPT를 사용할 수 있나요?','예. GitHub Copilot에서 제공되는 모델을 사용할 수 있습니다. 독립 실행 모드는 OpenAI 또는 Anthropic 키를 지원합니다.'],['Taskivator가 제 작업을 볼 수 있나요?','아니요. 보고서, 사양, 용어집, 스크린샷, 설정은 Taskivator로 전송되지 않습니다.'],['Team에는 무엇이 포함되나요?','5명용 5개 장치, 공유 QA 워크플로, 공유 프로젝트 설정, 일관된 심각도와 카테고리, 팀 설정 도구, 우선 지원이 포함됩니다.'],['등록 없이 연습할 수 있나요?','예. dry run을 사용하면 티켓이나 댓글을 만들지 않고 전체 보고서를 생성할 수 있습니다.'],['BugIt을 사용자 지정할 수 있나요?','예. 용어집, 카테고리, 플랫폼, 팀 스타일, 트래커 설정을 구성할 수 있습니다.'],['스크린샷을 지원하나요?','예. 이미지를 채팅에 붙여 넣고 생성된 보고서를 확인한 뒤 등록할 수 있습니다.'],['업데이트는 어떻게 작동하나요?','BugIt은 설정을 백업하고 서명된 업데이트를 검증하며 기존 설정을 보존합니다.'],['라이선스가 만료되면 어떻게 되나요?','로컬 파일과 설정은 유지됩니다. 등록 기능은 활성 라이선스가 필요합니다.'],['지원은 어떻게 받나요?','BugIt 대시보드에서 지원 티켓을 등록하세요. 기밀 프로젝트 정보는 포함하지 않아도 됩니다.']]},docs:{getting:'시작하기',user:'사용자 가이드',license:'라이선스 계약',privacy:'개인정보 처리방침',support:'지원'}}));
add('zh',merge(i18n.ja,{name:'中文',nav:{features:'功能',integrations:'集成',pricing:'价格',docs:'文档',faq:'FAQ'},cta:{early:'抢先体验',demo:'观看演示'},hero:{title:'会学习你工作流的 <span>QA 代理</span>。',subtitle:'把粗略测试笔记变成清晰、已审阅的缺陷单，并在几秒内提交到你的跟踪器。'},pricing:{soloTitle:'抢先体验 · 限量',teamTitle:'团队许可证 · 限量',seats:'5 席位',perYear:'/年',limited:'限时价格',soloRegular:'常规价格 $59.99/年',teamRegular:'常规价格 $249.99/年',teamCta:'获取团队许可证'},faq:{title:'购买前，先把问题说清楚。',items:[['BugIt 会自动提交缺陷吗？','不会。每个工单和评论都会先显示预览，提交前你必须输入 “yes”。'],['哪些跟踪器有内置测试映射？','Jira 和 Azure DevOps 有内置且经过测试的字段映射。其他工具通过你自己的 MCP 服务器连接。'],['我需要 GitHub Copilot 吗？','推荐使用，也是最简单的方式。BugIt 也可以使用你自己的 OpenAI 或 Anthropic 密钥独立运行。'],['可以使用 Claude、Gemini 或 GPT 吗？','可以。在 GitHub Copilot 中使用你的计划可用的模型。独立模式支持 OpenAI 或 Anthropic。'],['Taskivator 会看到我的工作吗？','不会。缺陷报告、规格、术语表、截图和设置不会发送给 Taskivator。'],['Team 包含什么？','Team 包含 5 个用户的 5 台设备、共享 QA 工作流、共享项目配置、一致的严重级别与分类、团队设置工具和优先支持。'],['可以不提交就练习吗？','可以。使用 dry run 可生成完整报告，而不会创建工单、评论或通知。'],['可以自定义 BugIt 吗？','可以。你可以配置术语表、分类、平台、团队风格和跟踪器设置。'],['BugIt 支持截图吗？','支持。把图片粘贴到聊天中，提交前先检查生成的报告。'],['更新如何工作？','BugIt 会备份设置、验证签名更新，并保留你的配置。'],['许可证到期会怎样？','你的本地文件和设置会保留。提交功能需要有效许可证。'],['如何获得支持？','先让 AI 助手诊断问题，然后运行 Check status 或 Check readiness。如果仍需帮助，请从 BugIt 仪表盘提交支持工单，无需包含机密项目信息。']]},docs:{getting:'快速开始',user:'用户指南',license:'许可协议',privacy:'隐私政策',support:'支持',supportDesc:'获取帮助并提交支持工单。'}}));
add('ru',merge(i18n.en,{name:'Русский',nav:{features:'Функции',integrations:'Интеграции',pricing:'Цены',docs:'Документация',faq:'FAQ'},cta:{early:'Ранний доступ',demo:'Смотреть демо'},hero:{title:'QA-агент, который <span>изучает</span> ваш рабочий процесс.',subtitle:'Превращает черновые тестовые заметки в аккуратные проверенные баг-тикеты за секунды.'},pricing:{soloTitle:'РАННИЙ ДОСТУП · ОГРАНИЧЕНО',teamTitle:'КОМАНДНАЯ ЛИЦЕНЗИЯ · ОГРАНИЧЕНО',seats:'5 МЕСТ',perYear:'/год',limited:'Ограниченная цена',soloRegular:'Обычная цена $59.99/год',teamRegular:'Обычная цена $249.99/год',soloDevice:'1 устройство (1 пользователь)',allFeatures:'Все функции включены',updates:'Бесплатные обновления v1.x при активной лицензии',docs:'Документация и руководства',support:'Поддержка по email',teamDevices:'5 устройств (5 пользователей)',teamWorkflow:'Общий QA-процесс',teamConfig:'Общая конфигурация проекта',teamSeverity:'Единые уровни важности и категории',teamTools:'Инструменты настройки команды',priority:'Приоритетная поддержка',teamCta:'Получить командную лицензию'},integrations:{eyebrow:'РАБОТАЕТ С ВАШИМИ ИНСТРУМЕНТАМИ',title:'Подключите инструменты, которыми уже пользуетесь.',lede:'Jira и Azure DevOps имеют встроенное проверенное сопоставление полей. Остальные инструменты подключаются через ваш MCP-сервер.',builtin:'ВСТРОЕННОЕ ПРОВЕРЕННОЕ СОПОСТАВЛЕНИЕ',mcp:'ЧЕРЕЗ ВАШ MCP-СЕРВЕР',crash:'СБОИ И ТЕСТЫ',knowledge:'ЗНАНИЯ И СОВМЕСТНАЯ РАБОТА',note:'⌁ Включите инструмент в настройке. Подключите один раз. Используйте везде.'},faq:{title:'Детали запуска без сюрпризов.',items:[['BugIt отправляет баги автоматически?','Нет. Каждый тикет и комментарий сначала показывается в предпросмотре, а перед отправкой нужно ввести “yes”.'],['Какие трекеры имеют встроенное проверенное сопоставление?','Jira и Azure DevOps имеют встроенное проверенное сопоставление полей. Остальные инструменты подключаются через ваш MCP-сервер.'],['Нужен ли GitHub Copilot?','GitHub Copilot рекомендуется и является самым простым вариантом. BugIt также может работать автономно с вашим ключом OpenAI или Anthropic.'],['Можно ли использовать Claude, Gemini или GPT?','Да, через модели, доступные в вашем плане GitHub Copilot. Автономный режим поддерживает OpenAI или Anthropic.'],['Taskivator видит мою работу?','Нет. Отчёты, спецификации, глоссарий, скриншоты и настройки никогда не отправляются в Taskivator.'],['Что входит в Team?','Team включает 5 устройств для 5 пользователей, общий QA-процесс, общую конфигурацию проекта, единые уровни важности и категории, инструменты настройки команды и приоритетную поддержку.'],['Можно тренироваться без отправки?','Да. Используйте dry run, чтобы создать полный отчёт без тикетов, комментариев или уведомлений.'],['Можно настроить BugIt под себя?','Да. Можно настроить глоссарий, категории, платформы, стиль команды и параметры трекера.'],['Поддерживает ли BugIt скриншоты?','Да. Вставьте изображение в чат и проверьте отчёт перед отправкой.'],['Как работают обновления?','BugIt делает резервную копию настроек, проверяет подписанные обновления и сохраняет вашу конфигурацию.'],['Что будет после истечения лицензии?','Ваши локальные файлы и настройки сохранятся. Для отправки тикетов нужна активная лицензия.'],['Как получить поддержку?','Сначала попросите AI-ассистента диагностировать проблему, затем выполните Check status или Check readiness. Если решить не удалось, создайте обращение в поддержку в личном кабинете BugIt — конфиденциальные данные проекта указывать не нужно.']]},docs:{eyebrow:'ДОКУМЕНТАЦИЯ',getting:'Начало работы',gettingDesc:'Настройте BugIt за несколько минут.',user:'Руководство пользователя',userDesc:'Полное руководство по функциям и процессам.',license:'Лицензионное соглашение',licenseDesc:'Условия использования BugIt.',privacy:'Политика конфиденциальности',privacyDesc:'Как мы защищаем ваши данные.',faqDesc:'Ответы на частые вопросы.',support:'Поддержка',supportDesc:'Получите помощь и создайте обращение в поддержку.'}}));

add('pt-br',{name:'Português BR',nav:{features:'Recursos',integrations:'Integrações',pricing:'Preços',docs:'Documentação',faq:'FAQ'},cta:{early:'Acesso antecipado',demo:'Ver demo'},hero:{title:'O agente QA que <span>aprende</span> seu fluxo de trabalho.',subtitle:'Transforme notas de teste em tickets limpos e revisados, enviados ao seu tracker em segundos.'},metrics:{saved:'economizados por bug',dupe:'verificação de duplicatas',setup:'configuração',private:'privado por design'},under:{features:'✓ Todos os recursos incluídos',updates:'✓ Atualizações v1.x gratuitas',private:'✓ Privado por design'},mission:{style:'Estilo do projeto carregado',severity:'Matriz de severidade carregada',glossary:'Glossário sincronizado',duplicate:'Busca de duplicatas ativada',redaction:'Ocultação de PII ativada',generating:'Gerando relatório...'},report:{label:'RELATÓRIO DE BUG GERADO',title:'Botão de login deixa de responder após toques rápidos',severity:'Alta',preview:'Prévia no Jira',summaryTitle:'Resumo',summary:'O botão de login deixa de responder quando clicado repetidamente durante a autenticação. O usuário permanece na tela de login sem mensagem de erro.',pre:'Passos para reproduzir\n1. Abrir a página de login\n2. Inserir credenciais válidas\n3. Clicar rapidamente em Login\n4. Observar o estado do botão\n\nEsperado: O usuário entra uma vez.\nAtual: O botão trava e o login falha.',ready:'Prévia pronta. Aguardando sua confirmação.'},demo:{eyebrow:'VER EM AÇÃO',title:'Um agente. Diferentes mundos de QA.',subtitle:'Use para web, mobile, desktop, SaaS, fluxos corporativos ou jogos.',saas:'SaaS / App web',game:'QA de jogos',general:'Fluxo geral'},integrations:{eyebrow:'FUNCIONA COM SUAS FERRAMENTAS',title:'Conecte as ferramentas que você já usa.',lede:'Jira e Azure DevOps incluem mapeamento de campos integrado e testado. Outras ferramentas se conectam pelo seu próprio servidor MCP.',builtin:'MAPEAMENTO INTEGRADO E TESTADO',mcp:'PELO SEU SERVIDOR MCP',crash:'CRASH E TESTE',knowledge:'CONHECIMENTO E COLABORAÇÃO',note:'⌁ Ative qualquer ferramenta na configuração. Conecte uma vez. Use em todos os lugares.'},pricing:{soloTitle:'ACESSO ANTECIPADO · LIMITADO',teamTitle:'LICENÇA DE EQUIPE · LIMITADA',seats:'5 ASSENTOS',perYear:'/ano',limited:'Preço por tempo limitado',soloRegular:'Preço normal US$59,99/ano',teamRegular:'Preço normal US$249,99/ano',soloDevice:'1 dispositivo (1 usuário)',allFeatures:'Todos os recursos incluídos',updates:'Atualizações v1.x gratuitas enquanto ativa',docs:'Documentação e guias',support:'Suporte por email',teamDevices:'5 dispositivos (5 usuários)',teamWorkflow:'Fluxo QA compartilhado',teamConfig:'Configuração de projeto compartilhada',teamSeverity:'Severidades e categorias consistentes',teamTools:'Ferramentas de configuração de equipe',priority:'Suporte prioritário',teamCta:'Obter licença de equipe'},trust:{privateTitle:'▣ Privado por design',private:'Seu trabalho fica na sua máquina. Nós nunca armazenamos, treinamos ou vendemos seus dados.',telemetryTitle:'◌ Sem telemetria',telemetry:'Apenas verificações anônimas de licença para manter sua licença ativa.',previewTitle:'✓ Prévia antes de enviar',preview:'Você revisa cada ticket e digita “yes” para enviar.',backupsTitle:'◎ Backups locais',backups:'Suas configurações e atividades ficam na sua máquina. Backups fáceis a qualquer momento.',updatesTitle:'◇ Atualizações seguras',updates:'As atualizações são assinadas criptograficamente e verificadas antes da instalação.',vscodeTitle:'</> Roda no VS Code',vscode:'Nativo do VS Code. Nenhum outro app necessário.'},faq:{title:'Detalhes do lançamento, sem surpresas.',items:[['O BugIt cria bugs automaticamente?','Não. Todo ticket e comentário é mostrado em prévia primeiro, e você precisa digitar “yes” antes de enviar.'],['Quais trackers têm mapeamento integrado e testado?','Jira e Azure DevOps têm mapeamento de campos integrado e testado. Outras ferramentas se conectam pelo seu próprio servidor MCP.'],['Preciso do GitHub Copilot?','O GitHub Copilot é recomendado e é o caminho mais fácil. O BugIt também pode rodar em modo standalone com sua própria chave OpenAI ou Anthropic.'],['Posso usar Claude, Gemini ou GPT?','Sim. Dentro do GitHub Copilot, use os modelos disponíveis no seu plano. O modo standalone suporta OpenAI ou Anthropic.'],['A Taskivator vê meu trabalho?','Não. Seus relatórios, specs, glossário, capturas e configurações nunca são enviados para a Taskivator.'],['O que está incluído no Team?','Team inclui 5 dispositivos para 5 usuários, fluxo QA compartilhado, configuração de projeto compartilhada, severidades e categorias consistentes, ferramentas de configuração de equipe e suporte prioritário.'],['Posso praticar sem enviar?','Sim. Use dry run para gerar um relatório completo sem criar tickets, comentários ou notificações.'],['Posso personalizar o BugIt?','Sim. Você pode configurar glossário, categorias, plataformas, estilo da equipe e configurações do tracker.'],['O BugIt suporta capturas de tela?','Sim. Cole uma imagem no chat e revise o relatório gerado antes de enviar.'],['Como funcionam as atualizações?','O BugIt faz backup das configurações, verifica atualizações assinadas e preserva sua configuração.'],['O que acontece quando minha licença expira?','Seus arquivos e configurações locais permanecem. Recursos de envio exigem uma licença ativa.'],['Como recebo suporte?','Envie email para the in-app Support page. Não envie informações confidenciais do projeto.']]},docs:{eyebrow:'DOCUMENTAÇÃO',getting:'Primeiros passos',gettingDesc:'Configure o BugIt em minutos.',user:'Guia do usuário',userDesc:'Guia completo de recursos e fluxos.',license:'Contrato de licença',licenseDesc:'Termos de uso do BugIt.',privacy:'Política de privacidade',privacyDesc:'Como coletamos, usamos e protegemos seus dados.',supportDesc:'Receba ajuda e abra um chamado de suporte.',faqDesc:'Respostas para perguntas comuns.',support:'Suporte'},docPages:{homeTitle:'Documentação',homeIntro:'Tudo que você precisa para instalar, ativar, personalizar e usar o BugIt com segurança.',gettingTitle:'Primeiros passos',userTitle:'Guia do usuário',licenseTitle:'Contrato de licença',privacyTitle:'Política de privacidade',faqTitle:'FAQ',supportTitle:'Suporte',supportIntro:'Precisa de ajuda com configuração ou licença? Envie email para the in-app Support page.',download:'Baixar PDF',before:'Antes de enviar',beforeText:'Não inclua código-fonte confidencial, dados de clientes, tickets privados ou segredos.',sections:['Instale o VS Code e o GitHub Copilot, abra a pasta do BugIt, selecione BugIt QA Agent, cole sua chave de licença e digite Begin setup.','O guia cobre configuração, comandos diários, personalização, atualizações, backups, segurança e solução de problemas. O BugIt mostra uma prévia de cada relatório e só envia após aprovação.','O BugIt é licenciado, não vendido. Solo é um dispositivo por vez. Team inclui 5 dispositivos para 5 usuários. Atualizações v1.x gratuitas estão incluídas enquanto a licença estiver ativa.','A Taskivator não recebe seus relatórios, specs, glossário, capturas, código, configurações ou tickets. Apenas verificações anônimas de licença são usadas.']}});
add('it',{name:'Italiano',nav:{features:'Funzioni',integrations:'Integrazioni',pricing:'Prezzi',docs:'Documentazione',faq:'FAQ'},cta:{early:'Accesso anticipato',demo:'Guarda demo'},hero:{title:'L’agente QA che <span>impara</span> il tuo workflow.',subtitle:'Trasforma note di test grezze in ticket puliti e revisionati, inviati al tracker in pochi secondi.'},metrics:{saved:'risparmiati per bug',dupe:'controllo duplicati',setup:'configurazione',private:'privato per design'},under:{features:'✓ Tutte le funzioni incluse',updates:'✓ Aggiornamenti v1.x gratuiti',private:'✓ Privato per design'},mission:{style:'Stile del progetto caricato',severity:'Matrice di severità caricata',glossary:'Glossario sincronizzato',duplicate:'Ricerca duplicati attiva',redaction:'Oscuramento PII attivo',generating:'Generazione report...'},report:{label:'REPORT BUG GENERATO',title:'Il pulsante di login non risponde dopo tocchi rapidi',severity:'Alta',preview:'Anteprima Jira',summaryTitle:'Riepilogo',summary:'Il pulsante di login smette di rispondere quando viene cliccato ripetutamente durante l’autenticazione. L’utente resta nella schermata di login senza messaggi di errore.',pre:'Passi per riprodurre\n1. Aprire la pagina di login\n2. Inserire credenziali valide\n3. Cliccare rapidamente Login\n4. Osservare lo stato del pulsante\n\nRisultato atteso: L’utente accede una volta.\nRisultato effettivo: Il pulsante si blocca e il login fallisce.',ready:'Anteprima pronta. In attesa della tua conferma.'},pricing:{soloTitle:'ACCESSO ANTICIPATO · LIMITATO',teamTitle:'LICENZA TEAM · LIMITATA',seats:'5 POSTI',perYear:'/anno',limited:'Prezzo per tempo limitato',soloRegular:'Prezzo normale $59.99/anno',teamRegular:'Prezzo normale $249.99/anno',soloDevice:'1 dispositivo (1 utente)',allFeatures:'Tutte le funzioni incluse',updates:'Aggiornamenti v1.x gratuiti durante la licenza',docs:'Documentazione e guide',support:'Supporto via email',teamDevices:'5 dispositivi (5 utenti)',teamWorkflow:'Workflow QA condiviso',teamConfig:'Configurazione progetto condivisa',teamSeverity:'Severità e categorie coerenti',teamTools:'Strumenti di configurazione team',priority:'Supporto prioritario',teamCta:'Ottieni licenza Team'},faq:{title:'Dettagli di lancio, senza sorprese.',items:[['BugIt crea bug automaticamente?','No. Ogni ticket e commento viene mostrato in anteprima e devi digitare “yes” prima dell’invio.'],['Quali tracker hanno mapping integrato e testato?','Jira e Azure DevOps hanno mapping dei campi integrato e testato. Gli altri strumenti si collegano tramite il tuo server MCP.'],['Mi serve GitHub Copilot?','GitHub Copilot è consigliato ed è il modo più semplice. BugIt può anche funzionare standalone con una tua chiave OpenAI o Anthropic.'],['Posso usare Claude, Gemini o GPT?','Sì. In GitHub Copilot puoi usare i modelli disponibili nel tuo piano. La modalità standalone supporta OpenAI o Anthropic.'],['Taskivator vede il mio lavoro?','No. Report, specifiche, glossario, screenshot e impostazioni non vengono mai inviati a Taskivator.'],['Cosa include Team?','Team include 5 dispositivi per 5 utenti, workflow QA condiviso, configurazione progetto condivisa, severità e categorie coerenti, strumenti di configurazione team e supporto prioritario.'],['Posso esercitarmi senza inviare?','Sì. Usa dry run per generare un report completo senza creare ticket, commenti o notifiche.'],['Posso personalizzare BugIt?','Sì. Puoi configurare glossario, categorie, piattaforme, stile del team e impostazioni del tracker.'],['BugIt supporta gli screenshot?','Sì. Incolla un’immagine nella chat e controlla il report prima di inviarlo.'],['Come funzionano gli aggiornamenti?','BugIt esegue il backup delle impostazioni, verifica gli aggiornamenti firmati e conserva la configurazione.'],['Cosa succede quando la licenza scade?','I file e le impostazioni locali restano disponibili. Le funzioni di invio richiedono una licenza attiva.'],['Come ricevo supporto?','Scrivi a the in-app Support page. Non inviare informazioni riservate del progetto.']]},docs:{eyebrow:'DOCUMENTAZIONE',getting:'Introduzione',gettingDesc:'Configura BugIt in pochi minuti.',user:'Guida utente',userDesc:'Guida completa a funzioni e workflow.',license:'Contratto di licenza',licenseDesc:'Termini per usare BugIt.',privacy:'Informativa sulla privacy',privacyDesc:'Come raccogliamo, usiamo e proteggiamo i dati.',supportDesc:'Ottieni aiuto e apri un ticket di supporto.',faqDesc:'Risposte alle domande comuni.',support:'Supporto'},docPages:{homeTitle:'Documentazione',homeIntro:'Tutto ciò che serve per installare, attivare, personalizzare e usare BugIt in sicurezza.',gettingTitle:'Introduzione',userTitle:'Guida utente',licenseTitle:'Contratto di licenza',privacyTitle:'Informativa sulla privacy',faqTitle:'FAQ',supportTitle:'Supporto',supportIntro:'Serve aiuto con configurazione o licenza? Scrivi a the in-app Support page.',download:'Scarica PDF',before:'Prima di scrivere',beforeText:'Non includere codice sorgente riservato, dati clienti, ticket privati o segreti.',sections:['Installa VS Code e GitHub Copilot, apri la cartella BugIt, seleziona BugIt QA Agent, incolla la licenza e digita Begin setup.','La guida copre configurazione, comandi quotidiani, personalizzazione, aggiornamenti, backup, sicurezza e risoluzione problemi.','BugIt è concesso in licenza, non venduto. Solo usa un dispositivo alla volta. Team include 5 dispositivi per 5 utenti.','Taskivator non riceve report, specifiche, glossario, screenshot, codice, impostazioni o ticket. Vengono usati solo controlli anonimi della licenza.']}});


